#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007

uint64_t powmod(uint64_t base, uint64_t exponent) {
    uint64_t result = 1;
    while (exponent > 0) {
        if (exponent & 1) {
            result = (result * base) % MOD;
        }
        base = (base * base) % MOD;
        exponent >>= 1;
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        if (N <= 2) {
            printf("0\n");
        } else {
            uint64_t result = (powmod(2, N - 2) - 1 + MOD) % MOD;
            printf("%llu\n", result);
        }
    }
    return 0;
}

